import matplotlib; matplotlib.use("Agg"); import matplotlib.pyplot as plt; import matplotlib.patches as patches; import numpy as np; fig, ax = plt.subplots(figsize=(5, 4)); ax.set_aspect("equal"); ax.axis("off"); vertices = np.array([[0, 0], [4, 0], [0, 3]]); triangle = patches.Polygon(vertices, closed=True, fill=True, facecolor="#eaf2fb", edgecolor="#1a1a1a", linewidth=2); ax.add_patch(triangle); square_size = 0.3; right_angle = patches.Rectangle((0, 0), square_size, square_size, fill=False, edgecolor="#1a1a1a", linewidth=1.5); ax.add_patch(right_angle); ax.text(2, -0.4, "4", ha="center", va="center", fontsize=12); ax.text(-0.4, 1.5, "3", ha="center", va="center", fontsize=12); ax.text(2.3, 1.8, "5", ha="center", va="center", fontsize=12); ax.set_xlim(-1, 5); ax.set_ylim(-1, 4); plt.savefig("out.png", dpi=150)